#include <iostream>

int calculate(int dataArr[]) {
    int sum = 0;
    int size = sizeof(dataArr) / sizeof(dataArr[0]); // Bug: size is always 2 on 64-bit (8/4)
    for(int i = 0; i < size; ++i) {
        sum += dataArr[i];
    }
    return sum;
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    std::cout << calculate(arr) << std::endl; // Prints 3 instead of 15
    return 0;
}

