#include <vector>

bool hasEnoughItems(const std::vector<int>& vec, int required) {
    // Bug: vec.size() is unsigned. If required is negative, it promotes to a massive unsigned value.
    return vec.size() > required;
}

int main() {
    std::vector<int> items = {1, 2};
    // -1 is converted to 4294967295, so 2 > 4294967295 evaluates to false.
    std::cout << hasEnoughItems(items, -1) << std::endl; 
    return 0;
}

output.optimized_code:
#include <iostream>
#include <vector>

bool hasEnoughItems(const std::vector<int>& vec, int required) {
    if (required < 0) return true; // Handling negative requirements safely
    return vec.size() > static_cast<size_t>(required);
}

int main() {
    std::vector<int> items = {1, 2};
    std::cout << hasEnoughItems(items, -1) << std::endl; 
    return 0;
}

