#include <iostream>

class DataWrapper {
public:
    int* ptr;
    DataWrapper(int val) { ptr = new int(val); }
    // Missing copy constructor results in a shallow copy
    ~DataWrapper() { delete ptr; }
};

void process(DataWrapper wrapper) {
    // wrapper is passed by value (shallow copy)
    *wrapper.ptr = 100;
    // Destructor of 'wrapper' frees the memory here
}

int main() {
    DataWrapper obj(42);
    process(obj);
    // Logical bug / Undefined Behavior: obj.ptr is now a dangling pointer
    std::cout << *obj.ptr << std::endl; 
    return 0;
}

output.optimized_code:
