public:
    std::shared_ptr<int> ptr;
    DataWrapper(int val) : ptr(std::make_shared<int>(val)) {}
};

void process(DataWrapper wrapper) {
    *wrapper.ptr = 100;
}

int main() {
    DataWrapper obj(42);
    process(obj);
    std::cout << *obj.ptr << std::endl; 
    return 0;
}

